const delay = ms => new Promise(r => setTimeout(r, ms));
async function run() {
  const start = Date.now();
  await Promise.all([
    delay(100),
    delay(200),
    delay(150)
  ]);
  const elapsed = Date.now() - start;
  console.log(elapsed >= 200 && elapsed < 300);
}
run();

